export interface Person {
  id: string; name: string; alias: string[];
  born?: number; died?: number; diedHow?: string; hometown?: string;
  status: 'active' | 'arrested' | 'killed' | 'deceased' | 'fugitive';
  cartelIds?: string[];
  roles: { cartelId: string; role: string; startYear: number; endYear?: number }[];
  bloodRelatives?: { personId: string; relation: string }[];
  mentors?: string[];
  notes: string;
  wikipediaUrl?: string;
  photos?: { url: string; caption: string }[];
  netWorthUSD?: number; // estimated peak net worth
  salaryUSD?: number; // estimated annual earnings at peak
}
export interface Cartel {
  id: string; name: string; shortName: string; aliases: string[];
  color: string; foundedYear: number; dissolvedYear?: number;
  peakYears: [number, number]; founders: string[]; description: string;
  parentCartels?: string[]; spawnedCartels?: string[];
  primaryDrugs: string[]; status: 'active' | 'fragmented' | 'dissolved';
  headquarters: string; currentLeaders?: string[];
  wikipediaUrl?: string;
  logo?: string; // URL to cartel emblem/logo
  annualRevenueUSD?: number; // estimated annual revenue at peak
  peakNetWorthUSD?: number; // estimated total cartel wealth at peak
}
export interface TerritoryPeriod {
  cartelId: string; stateCode: string; startYear: number; endYear: number;
  control: 'dominant' | 'partial' | 'contested'; leaderId?: string;
}
export interface CartelWar {
  id: string; title: string; cartel1: string; cartel2: string;
  startYear: number; endYear?: number; states: string[];
  description: string; estimatedDeaths?: number; outcome?: string;
  lat: number; lng: number;
  personIds?: string[];
}
export interface TraffickingRoute {
  id: string; name: string; cartelId: string; startYear: number; endYear: number;
  drugType: string[]; waypoints: [number, number][]; type: 'land' | 'sea' | 'air';
  description: string; volume: 'low' | 'medium' | 'high' | 'massive';
}
export interface ViolenceHotspot {
  id: string; name: string; stateCode: string; lat: number; lng: number;
  startYear: number; endYear: number; peakYear: number; intensity: number;
  cause: string; cartelIds?: string[];
}
export interface HistoricalEvent {
  id: string; year: number; month?: number; title: string; description: string;
  type: 'bust'|'war'|'founding'|'assassination'|'arrest'|'split'|'alliance'|'massacre'|'death'|'escape'|'operation';
  cartelIds?: string[]; personIds?: string[]; stateCode?: string; location?: string;
  lat?: number; lng?: number; significance: 'low'|'medium'|'high'|'critical'; drugVolume?: string;
}
export interface CartelAttack {
  id: string; year: number; month?: number;
  attackerCartelId?: string; targetCartelId?: string;
  title: string; description: string;
  type: 'assassination'|'massacre'|'ambush'|'bombing'|'kidnapping'|'territorial'|'retaliation'|'bust'|'operation'|'arrest'|'founding'|'death'|'escape'|'war'|'mass_grave';
  lat: number; lng: number; stateCode?: string;
  killed?: number; significance: 'low'|'medium'|'high'|'critical';
  personIds?: string[]; // key figures killed/targeted
  wikipediaUrl?: string;
  drugVolume?: string;
}

