export interface MassViolenceSite {
  id: string;
  title: string;
  description: string;
  type: 'body_dump' | 'mass_grave' | 'burn_site' | 'hanging' | 'dismemberment';
  cartelId: string;
  targetCartelId?: string;
  lat: number; lng: number;
  stateCode: string;
  year: number; month?: number;
  victims?: number;
  found?: string; // how/when discovered
  wikipediaUrl?: string;
}

export interface NotableConnection {
  id: string;
  name: string;
  alias?: string;
  category: 'politician' | 'entertainment' | 'music' | 'sports' | 'law_enforcement' | 'business';
  role: string; // their public role
  connectionTo: string[]; // personIds they're connected to
  connectionType: string; // nature of connection
  year?: number; yearEnd?: number;
  description: string;
  significance: 'low' | 'medium' | 'high' | 'critical';
  status: 'convicted' | 'accused' | 'investigated' | 'documented' | 'deceased';
  wikipediaUrl?: string;
  nationality: string;
}

export interface DrugBust {
  id: string;
  title: string;
  year: number; month?: number;
  lat: number; lng: number;
  stateCode: string;
  cartelId?: string;
  personIds?: string[];
  drugs?: { type: string; kg: number; streetValueUSD?: number }[];
  cashUSD?: number;
  gunsSeized?: number;
  vehicles?: number;
  labs?: number;
  arrests?: number;
  significance: 'low' | 'medium' | 'high' | 'critical';
  description: string;
  agency: string; // DEA, Mexican Army, etc.
  operationName?: string; // DEA operation name e.g. 'Operation Cleanup'
  indictment?: boolean; // US federal indictment
  extradition?: boolean; // resulted in extradition
  usSentenceYears?: number;
  wikipediaUrl?: string;
}

